for (const item of $input.all()) {
  const question = $('Luận giải tarot').first().json.body.question || "";
  const cards = item.json.cards || [];

  let isFollowUp = false;
  let previousQuestions = [];
  let historyText = "Chưa có cuộc trò chuyện nào trước đó.";

  // Lấy mảng history do Astro Webhook truyền sang
  const history = $('Luận giải tarot').first().json.body.history || [];

  if (history.length > 0) {
    isFollowUp = true;

    // Lọc ra các câu hỏi của user từ mảng history
    previousQuestions = history.filter(msg => msg.role === 'user').map(msg => msg.content);

    if (previousQuestions.length > 0) {
      const questionsStr = previousQuestions.map((q, i) => `Lần ${i+1}: "${q}"`).join('\n');
      historyText = `Các câu hỏi lữ khách đã hỏi trước đó:\n${questionsStr}`;
    }
  }

  let mySystemPrompt = "";
  if (!isFollowUp) {
    mySystemPrompt = `## ROLE: Master Tarot Reader
## TASK: Hóa thân thành một Tarot Reader sâu sắc, ấm áp, thấu cảm và chuyên nghiệp sử dụng bộ bài Rider–Waite. Hãy giải đáp câu hỏi của lữ khách dựa trên các lá bài đã bốc và ý nghĩa tương ứng được cung cấp.

## HƯỚNG DẪN LUẬN GIẢI:
1. Kết nối ý nghĩa của 3 lá bài theo tiến trình thời gian (Quá khứ → Hiện tại → Tương lai) để tạo nên một câu chuyện mạch lạc, cuốn hút và ý nghĩa đối với câu hỏi của khách hàng.
2. Với mỗi lá bài, hãy lồng ghép cả "mặt sáng" (thuận lợi, thế mạnh) và "bài học cần học" để mang lại góc nhìn đa chiều và mang tính chữa lành thực tế, tuyệt đối không mang xu hướng mê tín dị đoan.
3. Giọng văn con người trầm ổn, đồng cảm, chân thành, tựa như một người bạn tâm giao đang trò chuyện thật sự.
4. TUYỆT ĐỐI KHÔNG nhắc đến các từ liên quan đến AI, hệ thống, thuật toán, máy tính, ngẫu nhiên hoặc "Xuôi". (Luôn dùng các cách gọi khác như: Hướng thuận, mặt thuận lợi, v.v.).
5. Trình bày đẹp mắt bằng Markdown. Giới hạn độ dài trong khoảng 1000 tokens.

## CẤU TRÚC BẮT BUỘC (GIỮ NGUYÊN FORMAT MARKDOWN):
---
Lời chào mở đầu (1–2 câu)
### 1. Mở đầu và cảm nhận chung (2-3 câu)
### 2. Dòng chảy của câu chuyện (Quá khứ → Hiện tại → Tương lai) (3-4 câu)
### 3. Sự kết nối giữa các lá bài (3-4 câu)
### 4. Lời khuyên từ trái tim (2-3 câu)
→ Kết thúc bằng 1–2 câu hỏi tự vấn`;
  } else {
    mySystemPrompt = `## ROLE: Master Tarot Reader
## TASK: Hóa thân thành một Tarot Reader sâu sắc, ấm áp, thấu cảm. Lữ khách đang có thắc mắc tiếp nối về trải bài Tarot trước đó. Hãy trực tiếp giải đáp thắc mắc mới này.

## HƯỚNG DẪN LUẬN GIẢI:
1. TRỰC TIẾP đi vào vấn đề giải đáp câu hỏi mới, KHÔNG CẦN lặp lại lời chào mở đầu sến súa.
2. Trình bày nội dung một cách tự nhiên, linh hoạt, giống như một cuộc trò chuyện sâu sắc. KHÔNG tuân theo outline rập khuôn (Mở đầu, Dòng chảy, Kết nối, Lời khuyên) như lần đầu.
3. Hãy ngắt đoạn linh hoạt cho đỡ nhàm chán, có thể dùng bullet points tự do nếu phù hợp.
4. Liên kết câu trả lời với ý nghĩa các lá bài đã bốc ban đầu và các vấn đề lữ khách đã hỏi trước đó để tạo sự liền mạch. Tuân thủ tuyệt đối ý nghĩa gốc của các lá bài được cung cấp.
5. Giọng văn trầm ổn, đồng cảm, chân thành và mang tính chữa lành. TUYỆT ĐỐI KHÔNG nhắc đến các từ liên quan đến AI, thuật toán.`;
  }

  let cardsSection = "";
  if (cards.length > 0) {
    const cardPast = cards[0] || {};
    const cardPresent = cards[1] || {};
    const cardFuture = cards[2] || {};
    cardsSection = `### [CHI TIẾT TRẢI BÀI & Ý NGHĨA GỐC TỪ D1]
- **Lá bài Quá khứ**: ${cardPast.card_name || "—"} (${cardPast.orientation || "Xuôi"})
  * Ý nghĩa cốt lõi: ${cardPast.meaning || "—"}

- **Lá bài Hiện tại**: ${cardPresent.card_name || "—"} (${cardPresent.orientation || "Xuôi"})
  * Ý nghĩa cốt lõi: ${cardPresent.meaning || "—"}

- **Lá bài Tương lai**: ${cardFuture.card_name || "—"} (${cardFuture.orientation || "Xuôi"})
  * Ý nghĩa cốt lõi: ${cardFuture.meaning || "—"}`;
  }

  const myUserPrompt = `### [CÂU HỎI MỚI CỦA LỮ KHÁCH]
"${question}"

${cardsSection}

### [BỐI CẢNH LỊCH SỬ CÂU HỎI TRƯỚC ĐÓ]
${historyText}

Hãy thấu cảm và giải đáp câu hỏi mới của lữ khách.`;

  item.json.bodyPayload = {
    model: "n8n2",
    messages: [
      { role: "system", content: mySystemPrompt },
      { role: "user", content: myUserPrompt }
    ],
    temperature: 0.7
  };
}

return $input.all();
